import sys

def count_light_blocks(n, s, a):
    """Count the number of light blocks in the sequence."""
    count = 0
    for window_size in range(1, n + 1):
        window_sum = 0
        for i in range(n):
            window_sum += a[i]
            if window_sum <= s:
                count += 1
            if i >= window_size:
                window_sum -= a[i - window_size]
    return count

def main():
    """Read input from stdin and write the answer to stdout."""
    n, s = map(int, sys.stdin.readline().split())
    a = list(map(int, sys.stdin.readline().split()))
    print(count_light_blocks(n, s, a))

if __name__ == "__main__":
    main()
